-- Final reporting controls; saved reports are deliberately create-and-read only in this release.
insert into public.permissions(key,name_ar,name_en) values('reports.export_confidential','تصدير التقارير السرية','Export confidential reports') on conflict(key) do nothing;
insert into public.role_permissions(role_id,permission_id) select r.id,p.id from public.roles r join public.permissions p on p.key='reports.export_confidential' where r.key='platform_owner' on conflict do nothing;
create or replace function public.protect_published_dashboard() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_table_name='dashboard_definitions' and old.status='published' then raise exception 'Published dashboard is immutable'; end if; if tg_table_name='dashboard_widgets' and exists(select 1 from public.dashboard_definitions d where d.id=coalesce(new.dashboard_id,old.dashboard_id) and d.status='published') then raise exception 'Published dashboard widgets are immutable'; end if; return coalesce(new,old); end $$;
create trigger dashboard_published_delete_guard before delete on public.dashboard_definitions for each row execute function public.protect_published_dashboard(); create trigger dashboard_widgets_published_insert_guard before insert on public.dashboard_widgets for each row execute function public.protect_published_dashboard(); create trigger dashboard_widgets_published_delete_guard before delete on public.dashboard_widgets for each row execute function public.protect_published_dashboard();
create or replace function public.publish_dashboard(p_dashboard uuid) returns void language plpgsql security definer set search_path=public as $$ declare d public.dashboard_definitions%rowtype; begin select * into d from public.dashboard_definitions where id=p_dashboard for update; if not found or d.status<>'approved' or not public.can_report('dashboards.manage',d.tenant_id,d.organization_id,d.facility_id) or not exists(select 1 from public.dashboard_widgets where dashboard_id=d.id) or exists(select 1 from public.dashboard_widgets w where w.dashboard_id=d.id and (w.display_order<0 or coalesce(w.title_ar,'')='' and coalesce(w.title_en,'')='' or w.widget_type not in ('kpi_card','counter','gauge','line','area','bar','stacked_bar','pie','donut','heatmap','trend','table','top_n','timeline','activity_feed') or w.configuration::text ~* '(javascript|<script|http:|https:|;|function)' or (w.report_version_id is not null and not exists(select 1 from public.report_versions v where v.id=w.report_version_id and v.status='published' and v.tenant_id=d.tenant_id and v.organization_id=d.organization_id and v.facility_id is not distinct from d.facility_id)))) or exists(select 1 from public.dashboard_widgets where dashboard_id=d.id group by display_order having count(*)>1) then raise exception 'Dashboard publication denied'; end if; perform set_config('app.reporting_controlled','on',true); update public.dashboard_definitions set status='published',updated_at=now(),updated_by=auth.uid() where id=d.id; perform public.append_audit_event(d.tenant_id,d.organization_id,d.facility_id,'dashboard.published','dashboard_definition',d.id,'{}'); end $$;
create or replace function public.create_saved_report(p_version uuid,p_name text,p_filters jsonb default '[]') returns uuid language plpgsql security definer set search_path=public as $$ declare v public.report_versions%rowtype; id uuid; begin select * into v from public.report_versions where id=p_version and status='published'; if not found or coalesce(trim(p_name),'')='' or not public.can_report('reports.view',v.tenant_id,v.organization_id,v.facility_id) or jsonb_typeof(p_filters)<>'array' or jsonb_array_length(p_filters)>20 or not public.validate_report_definition(jsonb_build_object('filters',p_filters),(select module_key from public.report_definitions where id=v.definition_id)) then raise exception 'Saved report denied'; end if; insert into public.saved_reports(tenant_id,organization_id,facility_id,report_version_id,name,filters,owner_id) values(v.tenant_id,v.organization_id,v.facility_id,v.id,trim(p_name),p_filters,auth.uid()) returning id into id; return id; end $$;
create or replace function public.request_report_export(p_run_id uuid,p_format text,p_language text) returns uuid language plpgsql security definer set search_path=public as $$ declare r public.report_runs%rowtype; id uuid; begin if p_format not in ('pdf','excel','csv') then raise exception 'Invalid report export format'; end if; if p_language not in ('ar','en','bilingual') then raise exception 'Invalid report export language'; end if; select * into r from public.report_runs where id=p_run_id and requested_by=auth.uid() for update; if not found or r.status<>'completed' or not public.can_report('reports.export',r.tenant_id,r.organization_id,r.facility_id) or (r.contains_confidential and not public.has_platform_permission('reports.export_confidential',r.tenant_id,r.organization_id,r.facility_id)) then raise exception 'Report export denied'; end if; insert into public.report_exports(tenant_id,organization_id,facility_id,report_run_id,format,language,requested_by,expires_at) values(r.tenant_id,r.organization_id,r.facility_id,r.id,p_format,p_language,auth.uid(),now()+interval '24 hours') returning id into id; perform public.append_audit_event(r.tenant_id,r.organization_id,r.facility_id,'report.export_requested','report_run',r.id,jsonb_build_object('format',p_format,'language',p_language)); return id; end $$;
revoke all on function public.protect_published_dashboard() from public,anon,authenticated; revoke all on function public.publish_dashboard(uuid),public.create_saved_report(uuid,text,jsonb),public.request_report_export(uuid,text,text) from public,anon; grant execute on function public.publish_dashboard(uuid),public.create_saved_report(uuid,text,jsonb),public.request_report_export(uuid,text,text) to authenticated;
